Level3.prototype.onStopToBigPot = function (item) { //soltar objetos en el boton grande

	console.log('watafaca ' + item.key);
	var state = item.game.state.getCurrentState();

	if (item.key == 'straberryDone' || item.key == 'lemonDone' || item.key == 'bananaDone') {

		var enHornoGrande = item.game.physics.arcade.overlap(item, state.fBigBtn);

		if (enHornoGrande && state.fBigBtn.flavor == 'none') {

			state.fBigBtn.flavor = item.key;
			state.fBigBtn.ingredientFlavor = item;
			item.x = state.fBigBtn.x;
			item.y = state.fBigBtn.y;

			if (state.fBigBtn.core !== 'none') {
				state.makeRecipe(item, state.fBigBtn);
			}

		} else if (state.fBigBtn.ingredientFlavor === item) {

			if (!enHornoGrande) {
				state.limpiarIngredienteHorno(state.fBigBtn, item);
				state.descartarConPoof(item);
			} else {
				item.x = state.fBigBtn.x;
				item.y = state.fBigBtn.y;
			}

		} else if (!enHornoGrande) {

			state.limpiarIngredienteHorno(state.fBigBtn, item);
			state.descartarConPoof(item);

			if (this.pot) {
				this.pot.myItemsCooking = 0;
				this.pot.cookingFlavor = null;
				this.pot.animations.play('idle');
			}

		} else {
			state.descartarConPoof(item);
		}

	}

};

		

