Level3.prototype.isCollinding = function (player,cannon) { //is collinding with cannons

	var cannonCost = cannon.upgradeCost;
	
	if(player.myCoins >= cannonCost && !cannon.upgrading){
		
		this.fUpgradeCost.text= cannonCost;
		this.fUpgradeCost.visible = true;

		if(cannon.cannonlevel<3){

		this.fUpgradeCannon.tint =  0xffffff;
		this.fUpgradeCannon.visible=true;

		if(this.wannaUpgrade){

			cannon.upgradeLevel();
			player.myCoins -= cannonCost;
			this.wannaUpgrade = false;
			this.guardarProgreso();
		}
		}else{
			this.fUpgradeCost.visible = false;
			this.fUpgradeCannon.tint =   0xBB2323;

		}
	}else{

			this.fUpgradeCost.visible = false;
			this.fUpgradeCannon.visible=false;
			this.fUpgradeCannon.tint =   0xBB2323;
	}
	if(this.wannaChange ){
		cannon.changeDirection();
		
		this.wannaChange =  false;
	}
	if(this.pickUped ){

		cannon.visible=false;
		player.myCannonsUpgrades.push(cannon.cannonlevel);
	//	cannon.timer.destroy();
		cannon.weapon.destroy();
		cannon.destroy();
		this.pickUped=false;
		player.myCannons++;
		player.myWeapons++;

		if (this.fDropCannonBtn) {
			this.fDropCannonBtn.visible = true;
		}

		this.guardarProgreso();
	
	}


}


