Level3.prototype.askHelp = function () {
this.fPlayer.body.bounce.set(0.1);
	if(this.fPlayer.hasKey){
console.log( 'this.puedeGanar ' + this.puedeGanar)
	if(this.puedeGanar){
		this.game.state.start("winScreen",true,true);
	}else{
	this.game.state.getCurrentState().moveUpperBanner('Destroy all zombies!');

	}
	
	
	}else{
	
		if(!this.askingHelp){
			this.game.state.getCurrentState().moveUpperBanner('HELP! BUY A KEY!');
			this.askingHelp = true;
			timer = this.game.time.create(false);
			timer.loop(2000, function(){

				this.askingHelp = false;
				timer.destroy();
			}, this);
			timer.start();
		}
		
	}

}

