Level3.prototype.update = function () {

	if (this._placedCannonsPendientes) {
		this.restaurarCannonsColocados(this._placedCannonsPendientes);
		this._placedCannonsPendientes = null;
	}

	this.fUpgradeCost.visible = false;
	this.fClientsRemain.text = Math.max(0, this.ClientesPorAtender - this.clientesYaAtendidos); //contador de clientes por atender
	this.fYourMoney.text = this.fPlayer.myCoins;
	this.fMoneyCount.text = this.fPlayer.myCoins;

	if (!this._saveTimer) {
		this._saveTimer = 0;
	}

	this._saveTimer += this.game.time.elapsed || 0;

	if (this._saveTimer >= 2000 && this.necesitaGuardarProgreso()) {
		this.guardarProgreso();
		this._saveTimer = 0;
	}

	this.houseColliding = this.game.physics.arcade.overlap(this.fPlayer , this.fStore, this.enterStore, null, this);
	this.elevatorColliding =this.game.physics.arcade.collide(this.fAscensor1 , this.fPlayer, this.elevatorAction, null, this);
	this.ladderCollider = this.game.physics.arcade.overlap(this.fPlayer , this.fEscaleras);
	this.cannonCollinding = this.game.physics.arcade.overlap(this.fPlayer , this.fCannons, this.isCollinding, null, this);
	this.cannonCollindingPlatform = this.game.physics.arcade.collide(this.fCannons , this.fPlatforms, this.cannonFireCheck, null, this);
	this.enemiCollinding = this.game.physics.arcade.collide(this.fPlayer , this.fEnemies, this.hitPlayer, function() {  if (this.fPlayer.enableObstacleCollide) {    return true;  }  return false;}, this);
	this.chickRoomCollide = this.game.physics.arcade.collide(this.fPlayer , this.fChickRoomUp, this.askHelp,null, this);
	this.chickRoomCollideZombie = this.game.physics.arcade.collide(this.fEnemies , this.fChickRoomUp, this.eatGirl,null, this);

	this.game.physics.arcade.overlap(this.fDirections , this.fEnemies, this.changeDirection, null, this);
	this.game.physics.arcade.overlap(this.fPlayer , this.fCoins, this.collectCoin, null, this);
	this.game.physics.arcade.collide(this.fCoins , this.fPlatforms);
	this.game.physics.arcade.collide(this.fCannons , this.fAscensor1);
	this.game.physics.arcade.collide(this.fPlayer , this.fWalls);
	this.game.physics.arcade.collide(this.fPlayer , this.fPipes);
	this.game.physics.arcade.collide(this.fEnemies , this.fWalls);
	//this.game.physics.arcade.collide(this.fEnemies , this.fCannons);//en caso de que ser requiera habilitar collision entre cannons y enemies
	
	this.game.physics.arcade.collide(this.fPlayer , this.fElevators);
	this.game.physics.arcade.collide(this.fPlayer , this.fPlatforms); 
	
	
	
	this.game.physics.arcade.overlap(this.weapon.bullets, this.fPlatforms, this.hitWall, null, this);
	this.game.physics.arcade.overlap(this.weapon.bullets, this.fEnemies, this.hitEnemy, null, this);



if(this.dragginFinalCandy){ //aparecer o desaparecer la flecha de la orden final
	this.fArrows_instancia_.visible=true; 

}else{
	this.fArrows_instancia_.visible=false;
}

if(this.doingOrder){
	this.fDenyOrderBtn.visible=true;
}else{

	this.fDenyOrderBtn.visible=false;
}

if(this.siguienteFaseClientes && this.siguienteFaseZombies){ //preparar siguiente nivel
	
	this.level++;

	if (this.fOleadaNumero) {
		this.fOleadaNumero.text = String(this.level);
	}

	this.aplicarCostosTiendaPorNivel();
	this.guardarProgreso();

	this.siguienteFaseZombies = false;
	this.siguienteFaseClientes = false;

}
//console.log("cliente " + this.ultimoClienteAtendido + ' '+ "zombies " + this.ultimoZobieEliminado);
if(this.ultimoClienteAtendido && this.ultimoZobieEliminado){ //preparar clientes y zombies para el siguiente nivel

	this.OldeadaEnCurso = false;
	console.log('pantalla de puntuacion y rewards');


	 var timer = this.game.time.create(false);
	  timer.loop(2000, function(){ //demorar un poco para emitir fin de oleada
	  	win.play('win');
	  	this.findeOleada(); 
	  	timer.destroy();
	  }, this);
	  timer.start();

	
	this.prepararClientes(true);
	this.prepararZombies(true);

	
}

if(!this.ladderCollider ){

	this.fPlayer.body.gravity.y = 800; //para retomar la gravedad despues de usar la escalerea

}

if(this.ladderCollider && this.usingLadder){
this.fPlayer.body.gravity.y=0;

}else{

	this.usingLadder =  false;
}
if(this.ladderCollider && !this.usingLadder){

this.fPlayer.body.velocity.y=0;
}



//activar o desactivar sabores o cores de caramelos segun el numero en bodega
this.game.state.getCurrentState().sincronizarBodegaSabores();


if(this.insideElevator){
	this.fPlayer.position.setTo(this.fAscensor1.x, this.fAscensor1.y);
}

if(!this.insideElevator && this.fPlayer.y>182){

if(this.fPlayer.y>182 && this.fAscensor1.y<325){

	this.fAscensor1.body.velocity.y=30;


}


}


if(this.fAscensor1.world.y<137){
	this.fAscensor1.y = 137;
	this.fAscensor1.body.velocity.y=0;
	
}


if(this.fAscensor1.world.y>325){

	this.fAscensor1.y = 325;
	this.fAscensor1.body.velocity.y=0;
	
}

if(this.fPlayer.myCoins<this.fKeyCost.text){ //costo de la llave

	this.fKeyBuyBtn.tint =  0xBB2323;

}else{
	if(this.fPlayer.hasKey){

		this.fKeyBuyBtn.tint =  0xBB2323;

	}else{

		this.canBuyKey = true;
		this.fKeyBuyBtn.tint= 0xffffff;
	}


}

if(this.fPlayer.myCoins<this.fRollValue.text && !this.fPlayer.hasBallMode){

	this.fBallModeBtn.tint= 0xBB2323;
}else{
	this.canBuyBallMode =  true;
	if(this.fPlayer.hasBallMode){
		this.fBallModeBtn.tint= 0xBB2323;
	}else{
		this.fBallModeBtn.tint= 0xffffff;
	}
	
}

	if(this.fPlayer.myCoins < this.fGunValue.text ){ //costo de la pistola
		

		this.fGunBuyBtn.tint = 0xBB2323;
		
		
		//this.fGunBuyBtn.inputEnabled = false;

	}else{

			if(!this.fShootBtn.visible){

				this.fGunBuyBtn.tint = 0xffffff;

			}else{
				
				this.fGunBuyBtn.tint = 0xBB2323;
			}
	
		//this.fGunBuyBtn.inputEnabled = true;
	}

	if(this.fPlayer.myCoins < this.fCannonValue.text){

		this.fCannonBuyBtn.tint = 0xBB2323;
		
	}else{
	
		this.fCannonBuyBtn.tint = 0xffffff;

	}





	if(this.fPlayer.myCannons>0){ //si tiene algun cannon 

		this.fDropCannonBtn.visible=true;
	}else{
		this.fDropCannonBtn.visible=false;
	}
	
	
	if(this.cannonCollinding){

		this.fPickUpButton.visible =  true;	
		this.fChangeDirBtn.visible =  true;


	}else{

		this.fUpgradeCannon.visible = false;
		this.fPickUpButton.visible =  false;
			this.fChangeDirBtn.visible =  false;	
	}


	if(!this.houseColliding){

		this.fEnterHouseBtn.visible=false;
	}

if(!this.elevatorColliding){

		this.fElevatorInn.visible=false;
	}

	
	
	
	if(this.fPlayer.body.touching.down && this.wannaJump && !this.doubleJumping){
				
				this.fPlayer.body.velocity.y = -this.jumpingPower;
				this.wannaJump = false;
				this.jumping = true;
				this.justJump = true;
				this.fShootBtn.visible = false;

	}

	else if(this.fPlayer.body.touching.down  ){ //si el jugador esta topando algo abajo
				
				if(this.justJump){
				this.fPlayer.animations.play('idle');	
				this.fPlayer.body.drag.x=980;
				
				
				this.justJump=false;
				}
				
				this.jumping = false;
				if(this.fPlayer.hasPistol){

					this.fShootBtn.visible = true; //re aparecer pistola en caso de que tenga despues de saltar
				}
			}


	else if(this.doubleJumping){
				
			this.doubleJumping = false;
			this.doubleJump = false;
			this.wannaJump = false;
			}
			

	if(this.jumping && this.doubleJump && this.wannaJump){
				
				this.doubleJumping = true;
				
				this.fPlayer.body.velocity.y = -this.jumpingPower;

				var lastEmitter = this.fPlayer.game.state.getCurrentState().LuckyEmitters.pop();
			
				lastEmitter.destroy();
				console.log('doubleJumpActivado');
				
			}
	


};




